#include <bits/stdc++.h>
using namespace std;
struct xy{
	string name;
	int nl,cj;
	void tg(){
		if(cj*1.2>=600){
			cout<<600<<endl;
		}else{
			cout<<int(cj*1.2)<<endl;
		}
	}
}gsx[10];
int n;
int main(){
	cin>>n;
	for(int i=0;i<n;i++){
		cin>>gsx[i].name>>gsx[i].nl>>gsx[i].cj;
		cout<<gsx[i].name<<" "<<gsx[i].nl+1<<" ";
		gsx[i].tg();
	}
	return 0;
}
